import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./CompanyPendingBugs.css";

export default function CompanyPendingBugs() {
  const [bugs, setBugs] = useState([]);
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data =>
        setBugs((data.bugs || []).filter(b => b.status === "submitted"))
      )
      .catch(err => console.error(err));
  }, [token]);

  // ===== UPDATE STATUS FUNCTION =====
  const updateStatus = async (id, status) => {
    try {
      let body = { status };

      // If marking duplicate → require original bug ID
      if (status === "duplicate") {
        const originalId = prompt("Enter Original Bug ID:");

        if (!originalId) {
          alert("Original Bug ID is required!");
          return;
        }

        body.duplicateOf = originalId;
      }

      await fetch(`http://localhost:5000/api/bugs/${id}/status`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(body),
      });

      // Remove bug from UI after action
      setBugs(prev => prev.filter(b => b._id !== id));

    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="company-page">

      {/* ===== TOP BAR ===== */}
      <div className="top-bar">
        <button
          className="back-btn"
          onClick={() => navigate("/company")}
        >
          ⬅ Back to Dashboard
        </button>

        <h1>🐞 Pending Bugs</h1>
      </div>

      {/* ===== BUG LIST ===== */}
      {bugs.length === 0 ? (
        <p className="muted">No pending bugs.</p>
      ) : (
        <div className="bug-grid">
          {bugs.map(bug => (
            <div className="bug-card" key={bug._id}>
              <h3>{bug.title}</h3>

              <div className="bug-id">
                ID: {bug._id}
              </div>

              <p className="description">
                {bug.description}
              </p>

              <div className="actions">
                <button
                  className="approve"
                  onClick={() => updateStatus(bug._id, "approved")}
                >
                  ✔ Approve
                </button>

                <button
                  className="reject"
                  onClick={() => updateStatus(bug._id, "rejected")}
                >
                  ✖ Reject
                </button>

                <button
                  className="duplicate"
                  onClick={() => updateStatus(bug._id, "duplicate")}
                >
                  ⚠ Duplicate
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
